    42→class Optimizer {
    43→ private:
    44→  /// @brief this stored the positions of rules in OptimizerRulesFeature::_rules
    45→  using RuleDatabase = std::vector<int>;
    46→
    47→  /// @brief the following struct keeps a container of ExecutionPlan objects
    48→  /// and has some automatic convenience functions.
    49→  struct PlanList {
    50→    using Entry =
    51→        std::pair<std::unique_ptr<ExecutionPlan>, RuleDatabase::iterator>;
    52→
    53→    std::deque<Entry, ResourceUsageAllocator<Entry, ResourceMonitor>> list;
    54→
    55→    explicit PlanList(ResourceMonitor& monitor) : list(monitor) {}
    56→
    57→    /// @brief get number of plans contained
    58→    size_t size() const noexcept { return list.size(); }
    59→
    60→    /// @brief check if empty
    61→    bool empty() const noexcept { return list.empty(); }
    62→
    63→    /// @brief pop the first one
    64→    Entry pop_front() {
    65→      auto p = std::move(list.front());
    66→      list.pop_front();
    67→      return p;
    68→    }
    69→
    70→    /// @brief push_back
    71→    void push_back(std::unique_ptr<ExecutionPlan> p,
    72→                   RuleDatabase::iterator rule) {
    73→      list.push_back({std::move(p), rule});
    74→    }
    75→
    76→    /// @brief swaps the two lists
    77→    void swap(PlanList& b) noexcept { list.swap(b.list); }
    78→
    79→    /// @brief clear, deletes all plans contained
    80→    void clear() noexcept { list.clear(); }
    81→  };
    82→
    83→ public:
    84→  /// @brief optimizer statistics
    85→  struct Stats {
    86→    int64_t rulesExecuted = 0;
    87→    int64_t rulesSkipped = 0;
    88→    int64_t plansCreated = 1;  // 1 for the initial plan
    89→
    90→    /// @brief map with execution times per rule, only populated in
    91→    /// case tracing is enabled, a nullptr otherwise!
    92→    std::unique_ptr<std::unordered_map<int, double>> executionTimes;
    93→
    94→    void toVelocyPack(velocypack::Builder& b) const;
    95→    static void toVelocyPackForCachedPlan(velocypack::Builder& b);
    96→  };
    97→
    98→  /// @brief constructor, this will initialize the rules database
    99→  /// the .cpp file includes Aql/OptimizerRules.h
   100→  /// and add all methods there to the rules database
   101→  explicit Optimizer(ResourceMonitor& resourceMonitor, size_t maxNumberOfPlans);
   102→
   103→  /// @brief disable rules in the given plan, using the predicate function
   104→  void disableRules(ExecutionPlan* plan,
   105→                    std::function<bool(OptimizerRule const&)> const& predicate);
   106→
   107→  /// @brief do the optimization, this does the optimization, the resulting
   108→  /// plans are all estimated, sorted by that estimate and can then be got
   109→  /// by getPlans, until the next initialize is called. Note that the optimizer
   110→  /// object takes ownership of the execution plan and will delete it
   111→  /// automatically on destruction. It will also have ownership of all the
   112→  /// newly created plans it recalls and will automatically delete them.
   113→  /// If you need to extract the plans from the optimizer use stealBest or
   114→  /// stealPlans.
   115→  void createPlans(std::unique_ptr<ExecutionPlan> p,
   116→                   QueryOptions const& queryOptions);
   117→
   118→  /// @brief add a plan to the optimizer
   119→  void addPlan(std::unique_ptr<ExecutionPlan>, OptimizerRule const&,
   120→               bool wasModified);
   121→
   122→  /// @brief add a plan to the optimizer and makes it rerun the current rule
   123→  /// again
   124→  void addPlanAndRerun(std::unique_ptr<ExecutionPlan>, OptimizerRule const&,
   125→                       bool wasModified);
   126→
   127→  /// @brief getPlans, ownership of the plans remains with the optimizer
   128→  auto const& getPlans() noexcept { return _plans.list; }
   129→
   130→  /// @brief stealBest, ownership of the plan is handed over to the caller,
   131→  /// all other plans are deleted
   132→  std::unique_ptr<ExecutionPlan> stealBest() {
   133→    if (_plans.empty()) {
   134→      return nullptr;
   135→    }
   136→    auto res = std::move(_plans.list.front());
   137→    _plans.list.clear();
   138→    return std::move(res.first);
   139→  }
   140→
   141→  bool runOnlyRequiredRules() const noexcept;
   142→
   143→  /// @brief numberOfPlans, returns the current number of plans in the system
   144→  /// this should be called from rules, it will consider those that the
   145→  /// current rules has already added
   146→  size_t numberOfPlans() const noexcept {
   147→    return _plans.size() + _newPlans.size() + 1;
   148→  }
   149→
   150→  void initializeRules(ExecutionPlan* plan, QueryOptions const& queryOptions);
   151→
   152→  void toVelocyPack(velocypack::Builder& b) const;
   153→
   154→ private:
   155→  /// @brief disable a specific rule
   156→  void disableRule(ExecutionPlan* plan, int level);
   157→
   158→  /// @brief disable a specific rule, by name
